import os
from google.cloud import storage
import joblib
import tempfile

class ModelLoader:
    
    def __init__(self):
        self.gcs_client = storage.Client()
        self.model_path = os.getenv("MODEL_PATH", "")

    def download_latest_model(self):
        bucket_name, *path_parts = self.model_path.split("/")
        path = "/".join(path_parts)
        bucket = self.gcs_client.get_bucket(bucket_name)
        blobs = bucket.list_blobs(prefix=path)
        
        latest_blob = None
        for blob in blobs:
            if not latest_blob or blob.time_created > latest_blob.time_created:
                latest_blob = blob
        
        _, temp_local_filename = tempfile.mkstemp()
        
        latest_blob.download_to_filename(temp_local_filename)
        print(f"Latest model {latest_blob.name} downloaded to {temp_local_filename}.")

        return joblib.load(temp_local_filename)

if __name__ == "__main__":
    model_loader = ModelLoader()
    model = model_loader.download_latest_model()